#include<cstdio>
#include<algorithm>
#include<cmath>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;int cnt[N],a[N],n,Q,T,A[N],L,R,Tm,ans[N],Ans,BK;
struct N1{int l,r,t,idx;}q[N];struct N2{int p,u,v;}t[N];
inline void add(const int &v){Ans-=(cnt[v]==1);++cnt[v];Ans+=(cnt[v]==1);}
inline void del(const int &v){Ans-=(cnt[v]==1);--cnt[v];Ans+=(cnt[v]==1);} 
inline void Tadd(){++Tm;int p=t[Tm].p,v=t[Tm].v;if(L<=p&&p<=R)del(a[p]),add(v);a[p]=v;}
inline void Tmns(){int p=t[Tm].p,u=t[Tm].u;--Tm;if(L<=p&&p<=R)del(a[p]),add(u);a[p]=u;}
int main()
{
//	FIN("data.in");FOUT("mine.out");
	n=read();int nQ=read();rep(1,n,i)a[i]=A[i]=read();BK=pow(n,0.666666666);
	while(nQ--)
	{
		if(read()==1){int p=read()+1,v=read();t[++T]=(N2){p,A[p],v};A[p]=v;}
		else{++Q;int l=read()+1,r=read()+1;q[Q]=(N1){l,r,T,Q};}
	}
	std::sort(q+1,q+Q+1,[&](const N1&x,const N1&y){return (x.l/BK)==(y.l/BK)?((x.r/BK)==(y.r/BK)?x.t<y.t:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=q[1].l-1;Tm=0;rep(1,Q,i)
	{
		while(R<q[i].r)add(a[++R]);while(L>q[i].l)add(a[--L]);
		while(R>q[i].r)del(a[R--]);while(L<q[i].l)del(a[L++]);
		while(Tm<q[i].t)Tadd();while(Tm>q[i].t)Tmns();ans[q[i].idx]=Ans;
	}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
